mapper.insert:
insert into reviews
(
meetup_id, member_id, content, rating
) values (
#{meetupId},
#{memberId}, #{content}, #{rating}
)

mapper.select:
select review_id as reviewId, meetup_id as meetupId, member_id as memberId, content, rating, likes_count as likesCount, views_count as viewsCount, is_public as isPublic, case when delete_yn = 'Y' then 1 else 0 end as deleteYn, to_char(created_at, 'YYYY-MM-DD HH24:MI:SS') as createdAt, to_char(updated_at, 'YYYY-MM-DD HH24:MI:SS') as updatedAt from reviews
where member_id = #{memberId}
order by review_id desc
